import React from 'react'
import TourCard from '../../shared/TourCard.jsx';
import tourData from '../../assets/data/tours'
import { Col} from 'reactstrap';

const FeaturedTour=()=>{
  return (
    <>
    
        {    tourData?.map(tour=>(
              <Col lg='3' className="mb-4" key={tour._id}>
                 <TourCard tour={tour}/>
                 </Col>
                
              ))
            
               }
             
    </>
  )
}

